args.sqlite_command:
DROP TABLE IF EXISTS J09A_temp;
CREATE TABLE J09A_temp AS
SELECT *
FROM decision_table
WHERE TOUR LIKE 'J09A%';
ALTER TABLE J09A_temp ADD COLUMN ENTSCHEIDUNG TEXT;

UPDATE J09A_temp
SET ENTSCHEIDUNG = (
  CASE
    WHEN (
      SELECT COUNT(DISTINCT t2.EQUNR)
      FROM J09A_temp t2
      WHERE t2.HAUS = J09A_temp.HAUS
    ) < 3 THEN 'KSA'
    ELSE 'EVU'
  END
);

UPDATE J09A_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 = 0;
UPDATE J09A_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 BETWEEN 500 AND 599;
UPDATE J09A_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 BETWEEN 900 AND 999;
UPDATE J09A_temp SET ENTSCHEIDUNG = 'EVU' WHERE CITY2 IN ('Wiblingwerde', 'Breckerfeld');

ALTER TABLE J09A_temp ADD COLUMN "Meter Reading (MR) Doc. No." TEXT;
ALTER TABLE J09A_temp ADD COLUMN TITLE TEXT;
ALTER TABLE J09A_temp ADD COLUMN FORENAME TEXT;
ALTER TABLE J09A_temp ADD COLUMN SURNAME TEXT;
ALTER TABLE J09A_temp ADD COLUMN STREET TEXT;
ALTER TABLE J09A_temp ADD COLUMN STREETNO TEXT;
ALTER TABLE J09A_temp ADD COLUMN SALES_TITLE TEXT;
ALTER TABLE J09A_temp ADD COLUMN SALES_FORENAME TEXT;
ALTER TABLE J09A_temp ADD COLUMN SALES_SURNAME TEXT;
ALTER TABLE J09A_temp ADD COLUMN SALES_STREET TEXT;
ALTER TABLE J09A_temp ADD COLUMN SALES_STREETNO TEXT;
ALTER TABLE J09A_temp ADD COLUMN SALES_POST_CODE1 INTEGER;
ALTER TABLE J09A_temp ADD COLUMN SALES_CITY1 TEXT;
ALTER TABLE J09A_temp ADD COLUMN SALES_CITY2 TEXT;
ALTER TABLE J09A_temp ADD COLUMN SALES_EMAIL TEXT;
ALTER TABLE J09A_temp ADD COLUMN NET_POST_CODE1 INTEGER;
ALTER TABLE J09A_temp ADD COLUMN NET_CITY1 TEXT;
ALTER TABLE J09A_temp ADD COLUMN NET_CITY2 TEXT;
ALTER TABLE J09A_temp ADD COLUMN NET_EMAIL TEXT;
ALTER TABLE J09A_temp ADD COLUMN INSTALLATION TEXT;

UPDATE J09A_temp
SET INSTALLATION = ANLAGE;

UPDATE J09A_temp
SET "Meter Reading (MR) Doc. No." = (
  SELECT e."Meter Reading (MR) Doc. No."
  FROM eablg e
  WHERE e.Installation = J09A_temp.INSTALLATION
  LIMIT 1
);

UPDATE J09A_temp
SET TITLE = (
      SELECT s.TITLE FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    FORENAME = (
      SELECT s.FORENAME FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    SURNAME = (
      SELECT s.SURNAME FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    STREET = (
      SELECT s.STREET FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    STREETNO = (
      SELECT s.STREETNO FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    SALES_POST_CODE1 = (
      SELECT s.POST_CODE1 FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    SALES_CITY1 = (
      SELECT s.CITY1 FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    SALES_CITY2 = (
      SELECT s.CITY2 FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    SALES_EMAIL = (
      SELECT s.EMAIL FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    NET_POST_CODE1 = (
      SELECT n.POST_CODE1 FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    NET_CITY1 = (
      SELECT n.CITY1 FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    NET_CITY2 = (
      SELECT n.CITY2 FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1
    ),
    NET_EMAIL = (
      SELECT n.EMAIL FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1
    );

UPDATE J09A_temp
SET TITLE = CASE WHEN TITLE IS NOT NULL THEN TITLE ELSE (SELECT n.TITLE FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1) END,
    FORENAME = CASE WHEN FORENAME IS NOT NULL THEN FORENAME ELSE (SELECT n.FORENAME FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1) END,
    SURNAME = CASE WHEN SURNAME IS NOT NULL THEN SURNAME ELSE (SELECT n.SURNAME FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1) END,
    STREET = CASE WHEN STREET IS NOT NULL THEN STREET ELSE (SELECT n.STREET FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1) END,
    STREETNO = CASE WHEN STREETNO IS NOT NULL THEN STREETNO ELSE (SELECT n.STREETNO FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1) END,
    POST_CODE1 = CASE WHEN TITLE IS NOT NULL THEN SALES_POST_CODE1 ELSE NET_POST_CODE1 END,
    CITY1 = CASE WHEN TITLE IS NOT NULL THEN SALES_CITY1 ELSE NET_CITY1 END,
    CITY2 = CASE WHEN TITLE IS NOT NULL THEN SALES_CITY2 ELSE NET_CITY2 END,
    EMAIL = CASE WHEN TITLE IS NOT NULL THEN SALES_EMAIL ELSE NET_EMAIL END;

UPDATE J09A_temp
SET NET_POST_CODE1 = NULL,
    NET_CITY1 = NULL,
    NET_CITY2 = NULL,
    NET_EMAIL = NULL
WHERE TITLE IS NOT NULL
  AND EXISTS (SELECT 1 FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR);

UPDATE J09A_temp
SET SALES_TITLE = NULL,
    SALES_FORENAME = NULL,
    SALES_SURNAME = NULL,
    SALES_STREET = NULL,
    SALES_STREETNO = NULL,
    SALES_POST_CODE1 = NULL,
    SALES_CITY1 = NULL,
    SALES_CITY2 = NULL,
    SALES_EMAIL = NULL
WHERE NOT EXISTS (SELECT 1 FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR);

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr("Record created on",1,4) = '2024'
  INTERSECT
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr("Record created on",1,4) = '2023'
);

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'DIRECT_MAIL'
WHERE EQUNR IN (
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Ablesung durch Kunden - SAP'
    AND substr("Record created on",1,4) = '2024'
  INTERSECT
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Ablesung durch Kunden - SAP'
    AND substr("Record created on",1,4) = '2023'
);
